        "jsCode": "const cvItems = $('CV | Analyze Angle').all();
const normalizedItems = $('Code | Gerar URL Normalizada1').all();
const rules = items.map(item => item.json);

const normalizedMap = {};
for (const n of normalizedItems) {
  if (n.json?.public_id) {
    normalizedMap[n.json.public_id] = n.json;
  }
}

function matchRule(filename, pattern) {
  const name = String(filename || '').toUpperCase();
  const p = String(pattern || '').toUpperCase();
  return p.split('+').every(part => {
    part = part.trim();
    if (part.startsWith('STARTS_WITH:')) return name.startsWith(part.replace('STARTS_WITH:', '').trim());
    if (part.startsWith('CONTAINS:')) return name.includes(part.replace('CONTAINS:', '').trim());
    return false;
  });
}

function verticalBucket(templateKey, objectHeight) {
  const h = Number(objectHeight || 0);
  if (!h) return templateKey;
  if (templateKey === 'template_01') {
    if (h <= 310) return 'template_01_low';
    if (h <= 370) return 'template_01_mid';
    return 'template_01_high';
  }
  if (templateKey === 'template_03') {
    if (h <= 360) return 'template_03_low';
    if (h <= 410) return 'template_03_mid';
    return 'template_03_high';
  }
  if (templateKey === 'template_05') {
    if (h <= 390) return 'template_05_low';
    return 'template_05_high';
  }
  if (templateKey === 'template_10') {
    if (h <= 230) return 'template_10_low';
    if (h <= 255) return 'template_10_mid';
    return 'template_10_high';
  }
  return templateKey;
}

return cvItems.map((cvItem, index) => {
  const cvData = cvItem.json || {};
  const normalized = normalizedMap[cvData.public_id]
    || normalizedItems[index]?.json
    || {};
  const original_filename =
    normalized.original_filename ||
    normalized.image_identifier ||
    cvData.original_filename ||
    cvData.image_identifier ||
    '';
  const public_id = normalized.public_id || cvData.public_id || '';
  let base_template_key = null;
  for (const rule of rules) {
    if (matchRule(original_filename, rule.pattern)) {
      base_template_key = rule.template_key;
      break;
    }
  }
  if (!base_template_key) base_template_key = 'template_01';
  const object_width  = Number(cvData.object_width  || normalized.object_width  || 1200);
  const object_height = Number(cvData.object_height || normalized.object_height || 1200);
  const template_key  = verticalBucket(base_template_key, object_height);
  return {
    json: {
      ...normalized,
      ...cvData,
      public_id,
      original_filename,
      image_identifier: original_filename,
      base_template_key,
      template_key,
      object_width,
      object_height,
    }
  };
});"
